#!/bin/bash

set -e
source ./images/tags.env


# Any global/shared resources (default namespace) defined here
cat > loadtest-helm.yaml <<YAML
# generated by loadgen.sh

apiVersion: apps/v1
kind: Deployment
metadata:
  name: roller
  labels:
    app: roller
spec:
  replicas: 1
  selector:
    matchLabels:
      app: roller
  template:
    metadata:
      labels:
        app: roller
    spec:
      containers:
      - name: controller
        image: bitnami/kubectl:latest
        command:
        - /bin/bash
        - -c
        - |
            while true; do
            	for i in {1..95}; do
            		echo "rolling ${i}"
            		kubectl -n loadgen-${i} patch helmrelease test-release --type=merge --patch "{ \"spec\": { \"values\": { \"foo\": \"$(date)\" } } }"
            	done
            	sleep 280
            done

---

apiVersion: apps/v1
kind: Deployment
metadata:
  labels:
    app.kubernetes.io/instance: flux-system
    app.kubernetes.io/part-of: flux
    control-plane: controller
  name: source-controller
  namespace: default
spec:
  replicas: 1
  selector:
    matchLabels:
      app: source-controller
  strategy:
    type: Recreate
  template:
    metadata:
      annotations:
        prometheus.io/port: "8080"
        prometheus.io/scrape: "true"
      labels:
        app: source-controller
        kubernetes.azure.com/mdsd-tag: mdsd.sourcecontroller
    spec:
      containers:
      - args:
        - --concurrent=2
        - --events-addr=
        - --watch-all-namespaces=false
        - --log-level=info
        - --log-encoding=json
        - --enable-leader-election
        - --storage-path=/data
        - --storage-adv-addr=source-controller.default.svc.cluster.local.
        - --helm-cache-max-size=20
        - --helm-cache-ttl=8h
        - --helm-cache-purge-interval=10m
        env:
        - name: RUNTIME_NAMESPACE
          valueFrom:
            fieldRef:
              fieldPath: metadata.namespace
        image: mcr.microsoft.com/oss/fluxcd/source-controller@sha256:ecc400fd6caf530a2d77611a615f386d7d20ab6b58d6c9da321654cba8212e0f
        imagePullPolicy: IfNotPresent
        livenessProbe:
          httpGet:
            path: /healthz
            port: healthz
        name: source-controller-manager
        ports:
        - containerPort: 9090
          name: http
          protocol: TCP
        - containerPort: 8080
          name: http-prom
          protocol: TCP
        - containerPort: 9440
          name: healthz
          protocol: TCP
        readinessProbe:
          httpGet:
            path: /
            port: http
        resources:
          limits:
            cpu: 1000m
            memory: 1Gi
          requests:
            cpu: 50m
            memory: 64Mi
        securityContext:
          allowPrivilegeEscalation: false
          capabilities:
            drop:
            - ALL
          readOnlyRootFilesystem: true
          runAsNonRoot: true
          runAsUser: 65534
          runAsGroup: 65534
          seccompProfile:
            type: RuntimeDefault
        volumeMounts:
        - mountPath: /data
          name: data
        - mountPath: /tmp
          name: tmp
      nodeSelector:
        kubernetes.io/os: linux
      securityContext:
        fsGroup: 1337
      # serviceAccountName: source-controller
      terminationGracePeriodSeconds: 10
      volumes:
      - emptyDir: {}
        name: data
      - emptyDir: {}
        name: tmp

---

apiVersion: source.toolkit.fluxcd.io/v1beta2
kind: GitRepository
metadata:
  name: repo
  namespace: default
spec:
  interval: 5m
  url: https://github.com/jveski/TEMP
  ref:
    branch: master
  
---

apiVersion: v1
kind: Service
metadata:
  labels:
    app.kubernetes.io/instance: flux-system
    app.kubernetes.io/part-of: flux
    control-plane: controller
  name: source-controller
  namespace: default
spec:
  ports:
  - name: http
    port: 80
    protocol: TCP
    targetPort: http
  selector:
    app: source-controller
  type: ClusterIP
YAML

for i in {0..10}; do
  if [ $((i%2)) -ne 0 ]; then
    continue
  fi
	cat >> loadtest-helm.yaml <<YAML
---

apiVersion: apps/v1
kind: Deployment
metadata:
  labels:
    app.kubernetes.io/instance: flux-system
    app.kubernetes.io/part-of: flux
    control-plane: controller
  name: helm-controller-${i}
  namespace: default
spec:
  replicas: 1
  selector:
    matchLabels:
      app: helm-controller-${i}
      flux-component: helm-controller
  template:
    metadata:
      annotations:
        prometheus.io/port: "8080"
        prometheus.io/scrape: "true"
      labels:
        app: helm-controller-${i}
        flux-component: helm-controller
        kubernetes.azure.com/mdsd-tag: mdsd.helmcontroller
    spec:
      containers:
      - args:
        - --concurrent=4
        - --events-addr=
        - --watch-all-namespaces=true
        - --log-level=info
        - --log-encoding=json
        - --enable-leader-election
        - --watch-label-selector=partition in (${i},$((i + 1)))
        env:
        - name: RUNTIME_NAMESPACE
          valueFrom:
            fieldRef:
              fieldPath: metadata.namespace
        image: mcr.microsoft.com/oss/fluxcd/helm-controller@sha256:e5ea4f63d472c5cb98a42dd6c5e56e4439d58b7dbf1ebe011b86294522fb0732
        imagePullPolicy: IfNotPresent
        livenessProbe:
          httpGet:
            path: /healthz
            port: healthz
        name: helm-controller-manager
        ports:
        - containerPort: 8080
          name: http-prom
          protocol: TCP
        - containerPort: 9440
          name: healthz
          protocol: TCP
        readinessProbe:
          httpGet:
            path: /readyz
            port: healthz
        resources:
          limits:
            cpu: 1000m
            memory: 1Gi
          requests:
            cpu: 100m
            memory: 64Mi
        securityContext:
          allowPrivilegeEscalation: false
          capabilities:
            drop:
            - ALL
          readOnlyRootFilesystem: true
          runAsNonRoot: true
          runAsUser: 65534
          runAsGroup: 65534
          seccompProfile:
            type: RuntimeDefault
        volumeMounts:
        - mountPath: /tmp
          name: temp
      securityContext:
        fsGroup: 1337
      nodeSelector:
        kubernetes.io/os: linux
      # serviceAccountName: helm-controller
      terminationGracePeriodSeconds: 600
      volumes:
      - emptyDir: {}
        name: temp
YAML
done

